```class Solution {
public:
    int minSwaps(string s) {
        int n = s.length();
        int open = 0, close = 0;
        for (char c : s) {
            if (c == '[') open++;
            else close++;
        }
        int res = abs(open - close);
        for (int i = 0; i < n; i++) {
            if (s[i] == '[') open--;
            else close--;
            if (open < 0) open++;
            if (close < 0) close++;
            res = min(res, abs(open - close));
        }
        return res;
    }
};```
